#include <stdio.h>
int max(int a, int b) { return a > b ? a : b; }
int main() {
    int n;
    scanf("%d", &n);
    int weights[n];
    for (int i = 0; i < n; i++) {
        scanf("%d", &weights[i]);
    }
    int maxWeight = 0;
    for (int i = 0; i < n; i++) {
        maxWeight = max(maxWeight, weights[i]);
    }
    printf("%d\n", maxWeight);
    return 0;
}

